+template <>
+__device__ __forceinline__ half clamp_inf_for_half(float const input) {
+  // clamp inf values to enable fp16 training
+  return input > 0.0f ? (half)min(input, HALF_FLT_MAX - 1000)
+                      : (half)max(input, -HALF_FLT_MAX + 1000);
